import React, { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useSelector, useDispatch } from 'react-redux';
import { fetchRestaurants, fetchCuisines } from '../store/slices/restaurantSlice';
import { addToCart } from '../store/slices/cartSlice';
import SmartRecommendations from '../components/AI/SmartRecommendations';
import UserPreferenceSetup from '../components/AI/UserPreferenceSetup';

const SimpleHome = () => {
  const dispatch = useDispatch();
  const restaurants = useSelector((state) => state.restaurants);
  const cuisines = useSelector((state) => state.cuisines);
  const [featuredRestaurants, setFeaturedRestaurants] = useState([]);
  const [showPreferenceSetup, setShowPreferenceSetup] = useState(false);
  const [hasPreferences, setHasPreferences] = useState(false);

  useEffect(() => {
    dispatch(fetchRestaurants());
    dispatch(fetchCuisines());
  }, []);

  useEffect(() => {
    if (restaurants.length > 0) {
      setFeaturedRestaurants(restaurants.slice(0, 6));
    }
  }, [restaurants]);

  useEffect(() => {
    // Check if user has set preferences
    const savedPreferences = localStorage.getItem('userMealPreferences');
    setHasPreferences(!!savedPreferences);
  }, []);

  return (
    <div className="min-h-screen bg-gray-50">
      {/* Hero Section */}
      <section className="relative bg-gradient-to-br from-orange-500 via-red-500 to-pink-600 text-white py-20 overflow-hidden">
        {/* Animated Background Elements */}
        <div className="absolute inset-0 overflow-hidden">
          <div className="absolute -top-4 -left-4 w-72 h-72 bg-white opacity-10 rounded-full animate-pulse"></div>
          <div className="absolute top-20 right-10 w-32 h-32 bg-yellow-300 opacity-20 rounded-full animate-bounce" style={{animationDelay: '1s'}}></div>
          <div className="absolute bottom-10 left-20 w-48 h-48 bg-white opacity-5 rounded-full animate-pulse" style={{animationDelay: '2s'}}></div>
          <div className="absolute top-1/2 right-1/4 w-16 h-16 bg-orange-300 opacity-30 rounded-full animate-ping" style={{animationDelay: '0.5s'}}></div>
        </div>

        <div className="relative max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 text-center">
          <div className="animate-fade-in-up">
            <h1 className="text-4xl md:text-6xl font-bold mb-6 bg-gradient-to-r from-white to-yellow-200 bg-clip-text text-transparent animate-pulse">
              Delicious Food from Tamil Nadu
            </h1>
            <p className="text-xl md:text-2xl mb-8 animate-fade-in-up" style={{animationDelay: '0.3s'}}>
              Order from the best restaurants in Chennai, Madurai, Coimbatore & more
            </p>
            <div className="flex flex-col sm:flex-row gap-4 justify-center animate-fade-in-up" style={{animationDelay: '0.6s'}}>
              <Link
                to="/restaurants"
                className="group bg-white text-orange-600 px-8 py-4 rounded-full font-semibold hover:bg-yellow-100 transition-all duration-300 transform hover:scale-105 hover:shadow-2xl"
              >
                <span className="flex items-center justify-center space-x-2">
                  <span>Order Now</span>
                  <span className="group-hover:translate-x-1 transition-transform duration-300">→</span>
                </span>
              </Link>
              <Link
                to="/dish-search"
                className="group border-2 border-white text-white px-8 py-4 rounded-full font-semibold hover:bg-white hover:text-orange-600 transition-all duration-300 transform hover:scale-105 hover:shadow-2xl"
              >
                <span className="flex items-center justify-center space-x-2">
                  <span>Search Dishes</span>
                  <span className="group-hover:rotate-12 transition-transform duration-300">🍛</span>
                </span>
              </Link>
            </div>
          </div>

          {/* Floating Food Icons */}
          <div className="absolute inset-0 pointer-events-none">
            <div className="absolute top-20 left-10 text-4xl animate-bounce" style={{animationDelay: '1s'}}>🍕</div>
            <div className="absolute top-32 right-20 text-3xl animate-bounce" style={{animationDelay: '2s'}}>🍔</div>
            <div className="absolute bottom-20 left-1/4 text-2xl animate-bounce" style={{animationDelay: '1.5s'}}>🍜</div>
            <div className="absolute bottom-32 right-10 text-3xl animate-bounce" style={{animationDelay: '0.8s'}}>🍛</div>
            <div className="absolute top-1/2 left-16 text-2xl animate-bounce" style={{animationDelay: '2.5s'}}>🥘</div>
          </div>
        </div>
      </section>

      {/* Popular Cuisines */}
      <section className="py-16">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <h2 className="text-3xl font-bold text-center mb-12">Popular Cuisines</h2>
          <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-6 gap-6">
            {[
              { name: 'South Indian', emoji: '🍛', count: '50+ dishes' },
              { name: 'Chettinad', emoji: '🌶️', count: '30+ dishes' },
              { name: 'Multi Cuisine', emoji: '🍽️', count: '40+ dishes' },
              { name: 'North Indian', emoji: '🍛', count: '25+ dishes' },
              { name: 'Beverages', emoji: '☕', count: '15+ drinks' }
            ].map((cuisine) => (
              <Link
                key={cuisine.name}
                to={`/restaurants?cuisine=${cuisine.name}`}
                className="text-center p-6 bg-white rounded-lg shadow-sm hover:shadow-md transition-shadow"
              >
                <div className="text-4xl mb-3">{cuisine.emoji}</div>
                <h3 className="font-semibold text-gray-900">{cuisine.name}</h3>
                <p className="text-sm text-gray-600">{cuisine.count}</p>
              </Link>
            ))}
          </div>
        </div>
      </section>

      {/* AI Smart Recommendations */}
      <section className="py-16 bg-white">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          {!hasPreferences ? (
            <div className="mb-8 p-6 bg-gradient-to-r from-purple-50 to-blue-50 rounded-lg border">
              <div className="flex items-center justify-between">
                <div className="flex items-center space-x-3">
                  <div className="text-2xl">🤖</div>
                  <div>
                    <h3 className="text-lg font-semibold text-gray-900">Get AI-Powered Meal Recommendations</h3>
                    <p className="text-gray-600">Set up your preferences for personalized food suggestions</p>
                  </div>
                </div>
                <button
                  onClick={() => setShowPreferenceSetup(true)}
                  className="bg-purple-500 text-white px-4 py-2 rounded-lg hover:bg-purple-600 transition-colors"
                >
                  Setup AI Preferences
                </button>
              </div>
            </div>
          ) : (
            <SmartRecommendations className="mb-8" maxRecommendations={8} />
          )}
        </div>
      </section>

      {/* Preference Setup Modal */}
      {showPreferenceSetup && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center p-4 z-50">
          <div className="bg-white rounded-lg max-w-4xl w-full max-h-96 overflow-y-auto">
            <UserPreferenceSetup 
              onComplete={(preferences) => {
                setHasPreferences(true);
                setShowPreferenceSetup(false);
              }}
            />
          </div>
        </div>
      )}

      {/* Featured restaurants */}
      <section className="py-16">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <h2 className="text-3xl font-bold text-center mb-12">Featured restaurants</h2>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
            {featuredRestaurants.map((restaurant) => (
              <Link
                key={restaurant.id}
                className="bg-white rounded-lg shadow-sm hover:shadow-lg transition-shadow overflow-hidden"
              >
                <img
                  src={restaurant.image}
                  alt={restaurant.name}
                  className="w-full h-48 object-cover"
                />
                <div className="p-6">
                  <div className="flex justify-between items-start mb-2">
                    <h3 className="text-xl font-semibold text-gray-900">
                      {restaurant.name}
                    </h3>
                    <div className="flex items-center">
                      <span className="text-yellow-400">⭐</span>
                      <span className="text-sm text-gray-600 ml-1">{restaurant.rating}</span>
                    </div>
                  </div>
                  <p className="text-gray-600 mb-2">{restaurant.cuisine}</p>
                  <p className="text-sm text-gray-500 mb-3">{restaurant.city}, {restaurant.area}</p>
                  <div className="flex justify-between items-center">
                    <span className="text-sm text-gray-600">{restaurant.deliveryTime}</span>
                    <span className="text-sm font-medium text-green-600">₹{restaurant.deliveryFee} delivery</span>
                  </div>
                </div>
              </Link>
            ))}
          </div>

          <div className="text-center mt-12">
            <Link
              to="/restaurants"
              className="bg-orange-500 text-white px-8 py-3 rounded-lg font-semibold hover:bg-orange-600 transition-colors"
            >
              View All Restaurants ({mockRestaurants.length})
            </Link>
          </div>
        </div>
      </section>

      {/* Quick Stats */}
      <section className="py-16 bg-gray-100">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="grid grid-cols-1 md:grid-cols-4 gap-8 text-center">
            <div>
              <div className="text-3xl font-bold text-orange-600 mb-2">{mockRestaurants.length}+</div>
              <div className="text-gray-600">Restaurants</div>
            </div>
            <div>
              <div className="text-3xl font-bold text-orange-600 mb-2">200+</div>
              <div className="text-gray-600">Dishes</div>
            </div>
            <div>
              <div className="text-3xl font-bold text-orange-600 mb-2">6</div>
              <div className="text-gray-600">Cities</div>
            </div>
            <div>
              <div className="text-3xl font-bold text-orange-600 mb-2">30 min</div>
              <div className="text-gray-600">Avg Delivery</div>
            </div>
          </div>
        </div>
      </section>
    </div>
  );
};

export default SimpleHome;
